def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    """Modify the processing-time matrix and select jobs to perturb.

    Args:
        current_sequence: current permutation of job indices (list of n ints)
        time_matrix:      n×m matrix of processing times (numpy array)
        m:                number of machines
        n:                number of jobs
    Returns:
        new_matrix:   modified n×m processing-time matrix (numpy array)
        perturb_jobs: list of 2–5 job indices to apply targeted local search on
    """
    new_matrix = time_matrix.copy()

    # Compute start and completion times
    start = np.zeros((n, m))
    comp = np.zeros((n, m))
    for j in range(m):
        for i in range(n):
            job = current_sequence[i]
            if i == 0 and j == 0:
                start[i][j] = 0
            elif i == 0:
                start[i][j] = comp[i][j-1]
            elif j == 0:
                start[i][j] = comp[i-1][j]
            else:
                start[i][j] = max(comp[i-1][j], comp[i][j-1])
            comp[i][j] = start[i][j] + time_matrix[job][j]

    # Identify critical path (longest path)
    i, j = n-1, m-1
    critical_jobs = []
    critical_machines = []
    while i >= 0 and j >= 0:
        job = current_sequence[i]
        critical_jobs.append(job)
        critical_machines.append(j)
        if i == 0 and j == 0:
            break
        if i == 0:
            j -= 1
        elif j == 0:
            i -= 1
        else:
            if comp[i-1][j] >= comp[i][j-1]:
                i -= 1
            else:
                j -= 1
    critical_jobs.reverse()
    critical_machines.reverse()

    # Calculate idle time before each operation on its machine
    machine_idle = {mach: 0 for mach in range(m)}
    job_idle_impact = {job: 0 for job in range(n)}
    for idx, (job, mach) in enumerate(zip(critical_jobs, critical_machines)):
        if idx == 0:
            idle = start[idx][mach]
        else:
            prev_i = current_sequence.index(critical_jobs[idx-1])
            idle = start[idx][mach] - comp[prev_i][mach] if comp[prev_i][mach] < start[idx][mach] else 0
        job_idle_impact[job] += idle
        machine_idle[mach] += idle

    # Compute total critical count per job
    job_critical_count = {job: 0 for job in range(n)}
    for job in critical_jobs:
        job_critical_count[job] += 1

    # Score jobs: mix of critical count and idle impact
    max_idle = max(job_idle_impact.values()) if max(job_idle_impact.values()) > 0 else 1
    scores = {job: job_critical_count[job] + job_idle_impact[job] / max_idle for job in range(n)}

    # Select bottleneck jobs (top 30% by score)
    sorted_jobs = sorted(range(n), key=lambda j: scores[j], reverse=True)
    threshold_idx = max(1, int(0.3 * n))
    bottleneck_jobs = sorted_jobs[:threshold_idx]

    # For each bottleneck job, find machine where it causes most idle time
    job_machine_idle = {job: [0]*m for job in range(n)}
    for job, mach in zip(critical_jobs, critical_machines):
        job_machine_idle[job][mach] += job_idle_impact[job]

    for job in bottleneck_jobs:
        if max(job_machine_idle[job]) > 0:
            worst_machine = np.argmax(job_machine_idle[job])
            new_matrix[job][worst_machine] *= 1.2  # Lower amplification for stability

    # Return top 2-5 jobs by score
    perturb_jobs = sorted_jobs[:max(2, min(5, n))]

    return new_matrix, perturb_jobs

