            elif j == 0:
                slack_matrix[i, j] = C[i-1, j]
            else:
                slack_matrix[i, j] = max(C[i-1, j], C[i, j-1])

    job_slack = np.min(slack_matrix, axis=1)
    job_slack = np.where(job_slack < 1e-6, 1e-6, job_slack)

    B = np.zeros((n, m))
    for i, job in enumerate(current_sequence):
