            B[i, j] = max(0, time_matrix[job, j] - np.mean(time_matrix[:, j]))

    job_centrality = np.sum(B, axis=1)
    centrality_rank = np.argsort(-job_centrality)

    perturb_jobs = []
    seen = set()
    for idx in centrality_rank:
        if len(perturb_jobs) >= 5:
            break
        if idx not in seen:
            perturb_jobs.append(int(idx))
