            if i not in seen:
                perturb_jobs.append(i)
    perturb_jobs = perturb_jobs[:5]

    for job_idx in perturb_jobs:
        noise_factor = 1.0 + np.random.uniform(0.1, 0.5) * (1.0 / (1.0 + job_slack[job_idx]))
        new_matrix[job_idx, :] *= noise_factor

    return new_matrix, perturb_jobs

