    new_matrix = time_matrix.copy()

    # Compute completion times for current sequence
    comp = np.zeros((n, m))
    for j in range(m):
        for i in range(n):
            job = current_sequence[i]
            if i == 0 and j == 0:
                comp[i][j] = time_matrix[job][j]
            elif i == 0:
                comp[i][j] = comp[i][j-1] + time_matrix[job][j]
            elif j == 0:
                comp[i][j] = comp[i-1][j] + time_matrix[job][j]
            else:
                comp[i][j] = max(comp[i-1][j], comp[i][j-1]) + time_matrix[job][j]

    # Compute flow pressure: for each job, sum of idle time it causes on next jobs
    pressure = np.zeros(n)
    for j in range(m - 1):
        for i in range(n - 1):
            job = current_sequence[i]
            next_job = current_sequence[i+1]
            idle = max(0, comp[i][j] - comp[i+1][j-1]) if j > 0 else max(0, comp[i][j] - comp[i+1][j])
            pressure[job] += idle
            pressure[next_job] += max(0, comp[i+1][j] - comp[i][j+1]) if j < m-1 else 0

    # Select top pressure jobs
    num_critical = min(5, max(2, n // 3))
    critical_indices = np.argsort(pressure)[-num_critical:][::-1]

    # For each critical job, find machine with max contribution to pressure
    for job in critical_indices:
        max_pressure_machine = 0
        max_val = -1
        for j in range(m - 1):
            for i in range(n - 1):
                if current_sequence[i] == job:
                    idle = max(0, comp[i][j] - comp[i+1][j-1]) if j > 0 else max(0, comp[i][j] - comp[i+1][j])
                    if idle > max_val:
                        max_val = idle
                        max_pressure_machine = j
        if max_val > 0:
            new_matrix[job][max_pressure_machine] *= 1.3

    perturb_jobs = sorted(critical_indices.tolist())[:min(5, n)]
    if len(perturb_jobs) < 2 and n >= 2:
        perturb_jobs = [0, 1]
    elif len(perturb_jobs) < 2:
        perturb_jobs = list(range(n))
    return new_matrix, perturb_jobs[:min(5, n)]

def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    new_matrix = time_matrix.copy().astype(float)

    # Forward pass: earliest completion times
    C = np.zeros((n, m))
    for i, job in enumerate(current_sequence):
        for j in range(m):
            if i == 0 and j == 0:
                C[i, j] = time_matrix[job, j]
            elif i == 0:
                C[i, j] = C[i, j-1] + time_matrix[job, j]
            elif j == 0:
                C[i, j] = C[i-1, j] + time_matrix[job, j]
            else:
                C[i, j] = max(C[i-1, j], C[i, j-1]) + time_matrix[job, j]
    makespan = C[-1, -1]

    # Backward pass: latest start times for each job-machine pair (reverse order)
    L = np.full((n, m), makespan)
    for idx in range(n - 1, -1, -1):
        job = current_sequence[idx]
        for j in range(m - 1, -1, -1):
            if idx == n - 1 and j == m - 1:
                L[idx, j] = makespan - time_matrix[job, j]
            elif idx == n - 1:
                L[idx, j] = L[idx, j + 1] - time_matrix[job, j]
            elif j == m - 1:
                L[idx, j] = L[idx + 1, j] - time_matrix[job, j]
            else:
                L[idx, j] = min(L[idx + 1, j], L[idx, j + 1]) - time_matrix[job, j]

    # Slack = latest start - earliest start (earliest start = C - processing time)
    slack = np.zeros(n)
    for idx, job in enumerate(current_sequence):
        for j in range(m):
            earliest_start = C[idx, j] - time_matrix[job, j]
            slack[job] += L[idx, j] - earliest_start

    # Jobs with smallest total slack are bottleneck (elasticity is low slack)
    num_critical = min(5, max(2, n // 3))
    critical_indices = np.argsort(slack)[:num_critical]

    # Apply randomized compression (multiply by 0.7–0.95) to bottleneck jobs
    for job in critical_indices:
        factor = np.random.uniform(0.7, 0.95)
        new_matrix[job, :] *= factor

    perturb_jobs = critical_indices.tolist()[:5]
    if len(perturb_jobs) < 2:
        for i in range(n):
            if len(perturb_jobs) >= 2:
                break
            if i not in perturb_jobs:
                perturb_jobs.append(i)

    return new_matrix, perturb_jobs

def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    new_matrix = time_matrix.copy().astype(float)
    comp = np.zeros((n, m))
    for idx, job in enumerate(current_sequence):
        if idx == 0:
            comp[job, 0] = time_matrix[job, 0]
            for k in range(1, m):
                comp[job, k] = comp[job, k-1] + time_matrix[job, k]
        else:
            prev = current_sequence[idx-1]
            comp[job, 0] = comp[prev, 0] + time_matrix[job, 0]
            for k in range(1, m):
                comp[job, k] = max(comp[job, k-1], comp[prev, k]) + time_matrix[job, k]

    slack_ratio = np.zeros(n)
    for job in current_sequence:
        pos = current_sequence.index(job)
        if pos == 0 or pos == n-1:
            slack_ratio[job] = 0.0
            continue
        left_job = current_sequence[pos-1]
        right_job = current_sequence[pos+1]
        total_slack = 0.0
        for k in range(m):
            if k == 0:
                alt_start = comp[left_job, 0]
            else:
                alt_start = max(comp[left_job, k], comp[left_job, k-1] + time_matrix[right_job, k-1])
            idle = alt_start - comp[left_job, k]
            if idle > 0:
                total_slack += idle
        job_variance = np.var(time_matrix[job, :])
        slack_ratio[job] = total_slack * (1 + job_variance)

    num_critical = min(3, n)
    critical_indices = np.argsort(slack_ratio)[-num_critical:][::-1]

    for job in critical_indices:
        for k in range(m):
            offset = np.random.uniform(-0.5, 0.5) * time_matrix[job, k]
            new_matrix[job, k] = max(1, time_matrix[job, k] + offset)

    perturb_jobs = critical_indices.tolist()
    return new_matrix, perturb_jobs

