def get_matrix_and_jobs(current_sequence: list, time_matrix: np.ndarray,
                         m: int, n: int) -> tuple:
    new_matrix = time_matrix.copy()

    # Global conflict score: sum of absolute differences to all other jobs
    conflict = np.zeros(n)
    for i in range(n):
        for j in range(n):
            if i != j:
                conflict[i] += np.sum(np.abs(time_matrix[i] - time_matrix[j]))

    # Criticality = conflict score (higher = more disruptive)
    num_critical = max(3, min(5, n // 4))
    critical_indices = np.argsort(conflict)[-num_critical:][::-1]

    # Non-linear exponential perturbation
    for job in critical_indices:
        for k in range(m):
            if np.random.rand() < 0.5:
                new_matrix[job, k] *= np.exp(0.5)
            else:
                new_matrix[job, k] *= np.exp(-0.5)

    perturb_jobs = critical_indices.tolist()[:min(5, len(critical_indices))]
    return new_matrix, perturb_jobs
